import React from "react";

const SearchBar = ({ setFilters }) => {
  return (
    <input
      placeholder="Search product..."
      onChange={(e) =>
        setFilters((prev) => ({ ...prev, q: e.target.value }))
      }
    />
  );
};

export default SearchBar;
